mapper.select:
    	/* com.erns.coching.favorite.mapper.FavoriteDAO.getList */

		SELECT 
			ZZ.*
		FROM 
			(	
				SELECT

				FROM T_FAVORITE_INF AA






						ORDER BY AA.RGT_DTTM DESC	


			) ZZ

			OFFSET #{offset} LIMIT #{rowSize}

mapper.insert:
    	/* com.erns.coching.favorite.mapper.FavoriteDAO.insert */


			SELECT nextval('seq_t_message_inf')


		INSERT INTO T_FAVORITE_INF (
				MEMB_SEQ
			, REF_CODE
			, REF_SEQ
			, RGT_DTTM

		) VALUES (

				#{membSeq		, jdbcType=INTEGER}
			, #{refCode		, jdbcType=VARCHAR}
			, #{refSeq		, jdbcType=INTEGER}
			, now()
		)

mapper.delete:
	/* com.erns.coching.favorite.mapper.FavoriteDAO.delete */

DELETE FROM T_FAVORITE_INF

	AND MEMB_SEQ 	= #{membSeq	, jdbcType=INTEGER}
	AND REF_CODE 	= #{refCode	, jdbcType=VARCHAR}
	AND REF_SEQ 	= #{refSeq	, jdbcType=INTEGER}
